{"code": "import json
import re

# Step 1: Get latest release version for each NPM package
latest_releases = {}

result_file = locals()['var_functions.query_db:36']
with open(result_file, 'r') as f:
    packages = json.load(f)

    for pkg in packages:
        name = pkg['Name']
        version = pkg['Version']
        version_info = pkg['VersionInfo']

        # Check if this is a release version
        if '"IsRelease": true' in version_info:
            # Extract ordinal
            ordinal_match = re.search(r'"Ordinal":\s*(\d+)', version_info)
            if ordinal_match:
                ordinal = int(ordinal_match.group(1))

                # Keep track of the highest ordinal for each package
                if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                    latest_releases[name] = version

print('__RESULT__:')
print(json.dumps({
    'message': f'Found {len(latest_releases)} packages with latest release versions',
    'sample': dict(list(latest_releases.items())[:5])
}))"}

{"code": "import json
import re

# Step 1: Find latest release version for each NPM package
latest_releases = {}

result_file = locals()['var_functions.query_db:36']
with open(result_file, 'r') as f:
    packages = json.load(f)

    for pkg in packages:
        name = pkg['Name']
        version = pkg['Version']
        version_info = pkg['VersionInfo']

        # Check if this is a release version
        if '"IsRelease": true' in version_info:
            # Extract ordinal
            ordinal_match = re.search(r'"Ordinal":\s*(\d+)', version_info)
            if ordinal_match:
                ordinal = int(ordinal_match.group(1))

                # Keep track of the highest ordinal for each package
                if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                    latest_releases[name] = {
                        'version': version,
                        'ordinal': ordinal
                    }

# Convert to list format for easier processing
latest_packages_list = []
for name, info in latest_releases.items():
    latest_packages_list.append({
        'Name': name,
        'Version': info['version'],
        'Ordinal': info['ordinal']
    })

print('__RESULT__:')
print(json.dumps({
    'count': len(latest_packages_list),
    'sample': latest_packages_list[:5]
}))"}

