        'Ordinal': info['ordinal']
    })

print('__RESULT__:')
print(json.dumps({
    'count': len(latest_packages_list),
    'sample': latest_packages_list[:5]
}))"}

{"code": "import json
import re

# Load latest packages
latest_packages_file = locals()['var_functions.query_db:36']
with open(latest_packages_file, 'r') as f:
    all_packages = json.load(f)

# Find latest release version for each package
latest_releases = {}
for pkg in all_packages:
    name = pkg['Name']
    version = pkg['Version']
    version_info = pkg['VersionInfo']

    if '"IsRelease": true' in version_info:
        ordinal_match = re.search(r'"Ordinal":\s*(\d+)', version_info)
        if ordinal_match:
            ordinal = int(ordinal_match.group(1))
            if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                latest_releases[name] = {
                    'version': version,
                    'ordinal': ordinal
                }

# Load project_packageversion mappings
project_mappings_file = locals()['var_functions.query_db:34']
with open(project_mappings_file, 'r') as f:
    project_mappings = json.load(f)

# Create a lookup for project names by package name and version
project_lookup = {}
for mapping in project_mappings:
    if mapping['System'] == 'NPM':
        key = (mapping['Name'], mapping['Version'])
        project_lookup[key] = mapping['ProjectName']

# Get project names for our latest packages
packages_with_projects = []
for name, info in latest_releases.items():
    key = (name, info['version'])
    if key in project_lookup:
        packages_with_projects.append({
            'Name': name,
            'Version': info['version'],
            'ProjectName': project_lookup[key]
        })

print('__RESULT__:')
print(json.dumps({
    'total_with_projects': len(packages_with_projects),
    'sample': packages_with_projects[:10]
}))"}

