function.arguments:
{"code": "import json
import re

# This will store the latest release version for each package
latest_releases = {}

# Load and process the data in chunks to avoid memory issues
result_file = locals()['var_functions.query_db:30']
with open(result_file, 'r') as f:
    # Read the entire file as JSON
    packages = json.load(f)

    for pkg in packages:
        name = pkg['Name']
        version = pkg['Version']
        version_info = pkg['VersionInfo']

        # Check if this is a release version
        if '"IsRelease": true' in version_info:
            # Extract ordinal
            ordinal_match = re.search(r'"Ordinal":\s*(\d+)', version_info)
            if ordinal_match:
                ordinal = int(ordinal_match.group(1))

                # Keep track of the highest ordinal for each package
                if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                    latest_releases[name] = {
                        'version': version,
                        'ordinal': ordinal
                    }

# Create list of packages with their latest version
latest_packages = [(name, info['version']) for name, info in latest_releases.items()]

print('__RESULT__:')
print(json.dumps({
    'total_latest_packages': len(latest_packages),
    'sample': latest_packages[:10]
}))"}

